// Pega todos os itens de entrada do node pesquisa_json_fields_contact3
const items = $items("pesquisa_json_fields_contact3");

// Junta todos os payload_fields de todos os itens
let template = items.flatMap(item => item.json.payload_fields || []);

// Se por algum motivo vier string JSON, converte
if (typeof template === "string") {
  template = JSON.parse(template);
}

// Obter os dados do payload
const payload =
  $node["fluxo_chamado"].json?.body?.payload ||
  $node["fluxo_chamado"].json?.body ||
  $node["fluxo_chamado"].json ||
  {};

// Função para substituir placeholders no template
const replacePlaceholders = (template, data) => {
  const stringified = JSON.stringify(template);
  const replaced = stringified.replace(/{{\s*(\w+)\s*}}/g, (_, key) => {
    const valor = data[key];
    if (valor !== undefined && valor !== null) {
      return String(valor);
    } else {
      console.warn(`Placeholder {{ ${key} }} não encontrado no payload.`);
      return '';
    }
  });
  return JSON.parse(replaced);
};

// Substituir os placeholders
let result = replacePlaceholders(template, payload);

// Remover campos inválidos
result = result.filter(field => {
  const value = field.field_value;
  if (
    value === '' ||
    value === '+' ||
    value === undefined ||
    value === null
  ) {
    console.warn(`Removendo o campo vazio ou inválido: ${field.key}`);
    return false;
  }
  return true;
});

// Retornar no formato esperado
return [
  {
    json: {
      custom_fields_values: result
    }
  }
];

