    const email      = fx.email ?? pu.email ?? "";
    const locationId = $node["pesquisa_location_crm1"].json.valor_variavel;

    const name = `${firstName}${lastName ? " " + lastName : ""}`.trim();

    // Helpers
    const nonEmpty = (v) => Array.isArray(v) && v.length > 0;

    const getCF = (nodeName) => {
      if ($node[nodeName]?.runIndex >= 0) {
        const viaItems = $items(nodeName, 0)?.json?.custom_fields_values;
        if (nonEmpty(viaItems)) return viaItems;

        const viaNode = $node[nodeName]?.json?.custom_fields_values;
        if (nonEmpty(viaNode)) return viaNode;
      }
      return null;
    };

    const cf =
      getCF("formata_campos_contact3") ||
      getCF("formata_campos_contact4") ||
      getCF("formata_campos_contact5") ||
      null;

    // removido assignedTo
    const body = { firstName, lastName, name, locationId };

    if (phone) body.phone = phone;   // inclui só se houver valor
    if (email) body.email = email;   // idem
    if (cf) body.customFields = cf;  // inclui apenas se não vazio

    return body;
  })()
) }}

