if (typeof template !== "object" || template === null) {
    throw new Error("O template payload_fields não é um objeto válido.");
}

// Obter os dados diretamente do "body" do webhook
const payload = $node["fluxo_chamado"].json["body"]["payload"];

// Criar uma cópia do payload e adicionar o campo "nome" concatenado com "sobrenome"
const payloadAtualizado = { 
    ...payload, 
    nome: `${payload.nome || ''} ${payload.sobrenome || ''}`.trim() 
};

// Função para substituir os placeholders
const replacePlaceholders = (template, data) => {
    return Object.keys(template).map(key => {
        let fieldValue = template[key];

        if (typeof fieldValue === "string") {
            // Substituir placeholders no formato {{ chave }}
            fieldValue = fieldValue.replace(/{{\s*(\w+)\s*}}/g, (_, key) => {
                return data[key] !== undefined ? data[key] : ''; // Substitui ou deixa vazio se não encontrado
            });
        }

        return { field: key, value: fieldValue };
    });
};

// Substituir os placeholders no template com os dados do webhook atualizado
let result = replacePlaceholders(template, payloadAtualizado);

// Retornar o resultado no formato esperado
return {
    custom_fields_values: result
};

